import { Button, Flex } from "@chakra-ui/react";
import React from "react";

const Pagination = ({ totalCount, handlePageChange, current_page }) => {
  return (
    <Flex justify="center" mt={6} wrap="wrap" gap={2}>
      {Array.from({ length: totalCount }, (_, i) => {
        const page = i + 1;
        const isActive = current_page === page;

        return (
          <Button
            key={page}
            size="sm"
            borderRadius="full"
            minW="36px"
            bg={isActive ? "#A435F0" : "white"}
            color={isActive ? "white" : "#1c1d1f"}
            border="1px solid #d1d7dc"
            _hover={{
              bg: isActive ? "#8710d8" : "#f7f9fa",
            }}
            onClick={() => handlePageChange(page)}
          >
            {page}
          </Button>
        );
      })}
    </Flex>
  );
};

export default Pagination;
